#include<bits/stdc++.h>
using namespace std;
const int N=2e5+10;
int n,m;
struct bcj
{
	int fa[N];
	void init()
	{
		for(int i=1;i<=n;i++)
		{
			fa[i]=i;
		}
	}
	int find(int x)
	{
		return(x==fa[x]?x:fa[x]=find(fa[x]));
	}
	void merge(int x,int y)
	{
		int a=find(x),b=find(y);
		if(a!=b)
		{
			fa[a]=b;
		}
	}
}a;
int b[N];
bool vis[N];
vector<int> mp[N];
int main()
{
	scanf("%d%d",&n,&m);
	for(int i=1;i<=m;i++)
	{
		int u,v;
		scanf("%d%d",&u,&v);
		mp[u].push_back(v);
		mp[v].push_back(u);
	}
	a.init();
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&b[i]);
	}
	stack<int> stk;
	int cnt=0;
	for(int i=n;i>=1;i--)
	{
		cnt++;
		int x=b[i];
		vis[x]=1;
		for(int j:mp[x])
		{
			if(a.find(x)!=a.find(j))
			{
				if(!vis[j])
				{
					continue;
				}
				a.merge(x,j);
				cnt--;
			}
		}
		stk.push(cnt);
	}
	while(!stk.empty())
	{
		int t=stk.top();
		if(t==1)
		{
			printf("YES\n");
		}
		else
		{
			printf("NO\n");
		}
		stk.pop();
	}
	return 0;
}
